package github.chains;

import spoon.Launcher;
import spoon.processing.Processor;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtReference;
import spoon.reflect.reference.CtTypeReference;

import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher
        Launcher launcher = new Launcher();

        // Set the source code directory
        launcher.addInputResource("/workspace/OCR4all/src/main/java");

        // Set the output directory
        launcher.setSourceOutputDirectory("/workspace/OCR4all/src/main/java");

        // Add the processor to replace StreamWriteException with JsonGenerationException
        launcher.addProcessor(new StreamWriteExceptionProcessor());

        // Run Spoon
        launcher.run();

        System.out.println("Transformation completed: StreamWriteException replaced with JsonGenerationException");
    }

    public static class StreamWriteExceptionProcessor implements Processor<CtType<?>> {
        @Override
        public void process(CtType<?> element) {
            // Find all references to com.fasterxml.jackson.core.exc.StreamWriteException
            element.filterChildren((CtTypeReference<?> ref) -> {
                if (ref.getQualifiedName().equals("com.fasterxml.jackson.core.exc.StreamWriteException")) {
                    // Replace with com.fasterxml.jackson.core.JsonGenerationException
                    ref.setQualifiedName("com.fasterxml.jackson.core.JsonGenerationException");
                    return true;
                }
                return false;
            }).forEach(ref -> {
                // Update imports as well
                List<CtImport> imports = element.getImports();
                for (CtImport imp : imports) {
                    if (imp.getReference() != null && 
                        imp.getReference().getQualifiedName().equals("com.fasterxml.jackson.core.exc.StreamWriteException")) {
                        // Remove old import
                        element.removeImport(imp);
                        // Add new import
                        CtImport newImport = element.getFactory().createImport(
                            element.getFactory().createTypeReference("com.fasterxml.jackson.core.JsonGenerationException"));
                        element.addImport(newImport);
                        break;
                    }
                }
            });
        }
    }
}

