package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Define the source directory
        String sourceDirectory = "/workspace/OCR4all/src/main/java";

        // Create a new launcher
        Launcher launcher = new Launcher();

        // Set the source directory
        launcher.addInputResource(sourceDirectory);

        // Set the output directory
        launcher.setSourceOutputDirectory(sourceDirectory);

        // Build the model
        CtModel model = launcher.buildModel();

        // Find all class references to StreamWriteException and replace them
        List<CtTypeReference<?>> streamWriteExceptionRefs = model.getElements(
            new TypeFilter<>(CtTypeReference.class)
        ).stream()
            .filter(ref -> "com.fasterxml.jackson.core.exc.StreamWriteException".equals(ref.getQualifiedName()))
            .toList();

        // Replace references to StreamWriteException with JsonGenerationException
        for (CtTypeReference<?> ref : streamWriteExceptionRefs) {
            // Replace the qualified name
            ref.setQualifiedName("com.fasterxml.jackson.core.JsonGenerationException");
        }

        // Find all import statements that reference StreamWriteException and replace them
        List<CtImport> imports = model.getElements(new TypeFilter<>(CtImport.class));
        for (CtImport imp : imports) {
            if (imp.getReference() != null && 
                "com.fasterxml.jackson.core.exc.StreamWriteException".equals(imp.getReference().getQualifiedName())) {
                // Create new import for JsonGenerationException
                CtTypeReference<?> newRef = launcher.getFactory().createTypeReference();
                newRef.setQualifiedName("com.fasterxml.jackson.core.JsonGenerationException");
                imp.setReference(newRef);
            }
        }

        // Print a summary of what was changed
        System.out.println("Fixed Jackson StreamWriteException references in " + sourceDirectory);
        System.out.println("Replaced com.fasterxml.jackson.core.exc.StreamWriteException with com.fasterxml.jackson.core.JsonGenerationException");

        // Write the modified model back to disk
        launcher.process();
    }
}

