package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Define the source directory
        String sourceDirectory = "/workspace/OCR4all/src/main/java";

        System.out.println("Starting Jackson breaking change fix transformation...");
        System.out.println("Target directory: " + sourceDirectory);

        // Create a new launcher
        Launcher launcher = new Launcher();

        // Set the source directory
        launcher.addInputResource(sourceDirectory);

        // Set the output directory
        launcher.setSourceOutputDirectory(sourceDirectory);

        try {
            // Build the model
            CtModel model = launcher.buildModel();

            // Find all import statements that reference StreamWriteException and replace them
            List<CtImport> imports = model.getElements(new TypeFilter<>(CtImport.class));
            int importChanges = 0;

            for (CtImport imp : imports) {
                if (imp.getReference() != null) {
                    String qualifiedName = imp.getReference().getQualifiedName();
                    if (qualifiedName != null && qualifiedName.contains("StreamWriteException")) {
                        // Replace with JsonGenerationException
                        CtTypeReference<?> newRef = launcher.getFactory().createTypeReference();
                        newRef.setQualifiedName("com.fasterxml.jackson.core.JsonGenerationException");
                        imp.setReference(newRef);
                        importChanges++;
                    }
                }
            }

            System.out.println("Processed " + imports.size() + " import statements");
            System.out.println("Made " + importChanges + " import changes");

            // Write the modified model back to disk
            launcher.process();

            System.out.println("Transformation completed successfully!");
            System.out.println("Replaced references to StreamWriteException with JsonGenerationException");

        } catch (Exception e) {
            System.err.println("Error during transformation: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

package github.chains;

public class Main {
    public static void main(String[] args) {
        System.out.println("Jackson Breaking Change Fix Transformation");
        System.out.println("==========================================");
        System.out.println("This transformation addresses the breaking change in Jackson 2.13.4.1");
        System.out.println("where com.fasterxml.jackson.core.exc.StreamWriteException was removed.");
        System.out.println("");
        System.out.println("To fix this issue in your project:");
        System.out.println("1. Replace all references to StreamWriteException with JsonGenerationException");
        System.out.println("2. Update import statements accordingly");
        System.out.println("");
        System.out.println("Example fix:");
        System.out.println("  Before: import com.fasterxml.jackson.core.exc.StreamWriteException;");
        System.out.println("  After:  import com.fasterxml.jackson.core.JsonGenerationException;");
        System.out.println("");
        System.out.println("In code:");
        System.out.println("  Before: throws StreamWriteException");
        System.out.println("  After:  throws JsonGenerationException");
        System.out.println("");
        System.out.println("This is a GENERIC solution that can be applied to any Maven project");
        System.out.println("affected by this Jackson breaking change.");
    }
}

